import { z } from 'zod';
import { insertAutoGeneratedProjectSchema, type AutoGeneratedProject } from '@shared/schemas/maintenance';

/**
 * Frontend validation schema for editing auto-generated projects
 * Extends the base schema with additional frontend-specific validations
 */
export const editAutoProjectSchema = z.object({
  title: z.string().min(1, 'Title is required').max(200, 'Title must be less than 200 characters'),
  description: z.string().min(1, 'Description is required').max(2000, 'Description must be less than 2000 characters'),
  suggestedType: z.enum(['repair', 'minor_rehab', 'major_rehab', 'replacement', 'not_sure']),
  suggestedPriority: z.enum(['low', 'medium', 'high', 'critical']),
  estimatedCost: z.number().positive('Cost must be positive').optional(),
});

/**
 * Form validation schema for accepting auto-projects
 * Used when converting auto-project to real project
 */
export const acceptAutoProjectSchema = z.object({
  title: z.string().min(1, 'Title is required').max(200, 'Title must be less than 200 characters'),
  description: z.string().min(1, 'Description is required').max(2000, 'Description must be less than 2000 characters'),
  type: z.enum(['repair', 'minor_rehab', 'major_rehab', 'replacement', 'not_sure']),
  priority: z.enum(['low', 'medium', 'high', 'critical']),
  totalBudget: z.number().positive('Budget must be positive').optional(),
  plannedStartDate: z.date().optional(),
  plannedEndDate: z.date().optional(),
  vendorId: z.string().uuid().optional(),
  // New workflow fields
  planningDescription: z.string().max(2000, 'Planning description must be less than 2000 characters').optional(),
  workStartDate: z.date().optional(),
  skipSubmission: z.boolean().optional(),
  skipPreWork: z.boolean().optional(),
  skipPostWork: z.boolean().optional(),
}).refine((data) => {
  // End date must be after start date
  if (data.plannedStartDate && data.plannedEndDate) {
    return data.plannedEndDate > data.plannedStartDate;
  }
  return true;
}, {
  message: "End date must be after start date",
  path: ["plannedEndDate"],
}).refine((data) => {
  // Work start date should be after planned start date if both are provided
  if (data.plannedStartDate && data.workStartDate) {
    return data.workStartDate >= data.plannedStartDate;
  }
  return true;
}, {
  message: "Work start date should be on or after planned start date",
  path: ["workStartDate"],
});

/**
 * Schema for dismissing auto-projects
 */
export const dismissAutoProjectSchema = z.object({
  reason: z.string().min(1, 'Please provide a reason for dismissing').max(500, 'Reason must be less than 500 characters'),
});

/**
 * Extended auto-generated project type with computed properties
 */
export interface AutoGeneratedProjectWithMetadata extends AutoGeneratedProject {
  // Computed confidence level
  confidenceLevel: 'low' | 'medium' | 'high';
  // Element information if available
  element?: {
    id: string;
    name: string;
    category: string;
    location?: string;
  };
  // Suggestion information if linked
  suggestion?: {
    id: string;
    reason: string;
    suggestedDate?: string;
  };
  // Estimated project duration (derived from metadata)
  estimatedDuration?: number;
  // Whether this auto-project can be edited
  canEdit: boolean;
  // Whether this auto-project can be accepted
  canAccept: boolean;
  // Whether this auto-project can be dismissed
  canDismiss: boolean;
}

/**
 * Response type for auto-generated projects API
 */
export interface AutoGeneratedProjectsResponse {
  autoProjects: AutoGeneratedProjectWithMetadata[];
  total: number;
  pending: number;
  accepted: number;
  dismissed: number;
  organizationId?: string;
  buildingId: string;
}

/**
 * Type for auto-project accept request
 */
export type AcceptAutoProjectRequest = z.infer<typeof acceptAutoProjectSchema>;

/**
 * Type for auto-project edit request
 */
export type EditAutoProjectRequest = z.infer<typeof editAutoProjectSchema>;

/**
 * Type for auto-project dismiss request
 */
export type DismissAutoProjectRequest = z.infer<typeof dismissAutoProjectSchema>;

/**
 * Auto-project action types for component props
 */
export interface AutoProjectActions {
  onView?: (autoProject: AutoGeneratedProjectWithMetadata) => void;
  onEdit?: (autoProject: AutoGeneratedProjectWithMetadata) => void;
  onAccept?: (autoProject: AutoGeneratedProjectWithMetadata) => void;
  onDismiss?: (autoProject: AutoGeneratedProjectWithMetadata) => void;
}

