/**
 * Utility function to get confidence level from score
 */
export function getConfidenceLevel(confidence?: number): 'low' | 'medium' | 'high' {
  if (!confidence) return 'low';
  
  if (confidence >= CONFIDENCE_LEVELS.high.min) return 'high';
  if (confidence >= CONFIDENCE_LEVELS.medium.min) return 'medium';
  return 'low';
}

/**
 * Utility function to format currency
 */
export function formatCurrency(amount?: number | string): string {
  if (!amount) return 'Not specified';
  
  const numAmount = typeof amount === 'string' ? parseFloat(amount) : amount;
  return new Intl.NumberFormat('en-CA', {
    style: 'currency',
    currency: 'CAD',
  }).format(numAmount);
}

/**
 * Utility function to format confidence percentage
 */
export function formatConfidence(confidence?: number): string {
  if (!confidence) return 'Unknown';
  return `${Math.round(confidence * 100)}%`;
}